func (r *subscriberRegistry) broadcast(snap Snapshot) {
	data, err := marshalSnapshot(snap)
	if err != nil {
		return
	}
	r.mu.Lock()
	defer r.mu.Unlock()
	for ch := range r.subs {
		select {
		case ch <- data:
		default:
			// #51 C5: the channel is full (a slow reader has not drained
			// its buffered frame). Drain the stale queued frame and
			// enqueue the new one, under r.mu - the same lock that
			// prevents a concurrent unregister/close (unregister above
			// takes r.mu before calling close(ch)), so this can never
			// race a close. Before this fix, the send above simply
			// failed and nothing replaced it, leaving the STALE frame in
			// place - a consistently slow consumer stayed perpetually
			// one frame behind forever, the opposite of what the old
			// comment here claimed.
			select {
			case <-ch:
			default:
			}
			select {
			case ch <- data:
			default:
				// the buffer was drained by nothing else (only this
				// goroutine, under r.mu, ever reads/writes this slot in
				// the drop path) - unreachable in practice, but never
				// block on it if it somehow is.
			}
		}
	}
}

